fun extGcd(a: Long, b: Long): Triple<Long, Long, Long> {
    if (a == 0L) return Triple(b, 0L, 1L)
    val (g, x1, y1) = extGcd(b % a, a)
    return Triple(g, y1 - (b / a) * x1, x1)
}

fun extendedGcdApplications(arr: IntArray): Int {
